sys_variable_value.value:
(function execute(inputs, outputs) {
    
    // 1. Initialize your Script Include
    var helper = new TimetableHelper(); 
    
    // 2. Call the main processing function
    // We pass the variables directly. The Script Include will handle:
    // - Data aggregation
    // - REST call to Gemini
    // - Creating the record in your separate "Result" table
    helper.processTimetableRequest(
        inputs.classes, 
        inputs.locations, 
        inputs.start_date, 
        inputs.end_date,
        inputs.ritm_sys_id // Useful for linking the result back to the request
    );

    gs.info("AUMS: Timetable Script Include triggered for RITM " + inputs.ritm_sys_id);

})(inputs, outputs);

